users={}
tokens={}
def register(username,password):
    if username in users:return{'error':'User exists'}
    if len(password)<8:return{'error':'Password too short'}
    hashed=hashlib.sha256(password.encode()).hexdigest()
    users[username]={'password':hashed,'joined':'2024-01-01'}
    return{'success':True,'user':username}
def login(username,password):
    user=users.get(username)
    if not user:return{'error':'Not found'}
    hashed=hashlib.sha256(password.encode()).hexdigest()
    if user['password']!=hashed:return{'error':'Wrong password'}
    token=f'token_{username}_abc123'
    tokens[token]=username
    return{'token':token}
def get_profile(token):
    username=tokens.get(token)
    if not username:return{'error':'Invalid token'}
    return{'username':username,'joined':users[username]['joined']}
