from collections import defaultdict
import time
app=FastAPI()
VALID_API_KEYS={'key-ada-123','key-mabel-456'}
request_log=defaultdict(list)
def validate_api_key(api_key:str):
    if api_key not in VALID_API_KEYS:
        raise HTTPException(status_code=401,detail='Invalid API key')
def rate_limit(client_ip:str,limit:int=5,window:int=60):
    now=time.time()
    request_log[client_ip]=[t for t in request_log[client_ip] if now-t<window]
    if len(request_log[client_ip])>=limit:
        raise HTTPException(status_code=429,detail='Rate limit exceeded')
    request_log[client_ip].append(now)
@app.get('/data')
def get_data(x_api_key:str=Header(...),x_forwarded_for:str=Header(default='127.0.0.1')):
    validate_api_key(x_api_key)
    rate_limit(x_forwarded_for)
